sql:
SELECT neighborhood_id, crime_id, year
FROM neighborhood_crime_rates
ORDER BY rate DESC;

SELECT prediction, method
FROM crime_predictions
WHERE neighborhood_id = 1 AND crime_id = 1;

SELECT density
FROM crime_density
WHERE neighborhood_id = 1 AND crime_id = 1;

SELECT rate
FROM neighborhood_crime_rates
WHERE year = 2022;

SELECT neighborhood_id, crime_id
FROM crime_statistics
WHERE year = (
  SELECT MAX(year)
  FROM crime_statistics
);

external_knowledge:
; Recent year refers to the last 12 months from the current date; 
; Homicide rates are calculated per 1000 residents; 
; Median income is a statistical measure indicating the middle value in a list of incomes, where half of the incomes are higher and half are lower; 
; The ranking of neighborhoods by crime rate helps in identifying areas with the most severe homicide issues.
